use std::rc::{Rc, Weak};

#[derive(Debug)]
pub struct BOSTree {
    /// The root node of the tree.
    pub root_node: Option<Rc<RefCell<BOSNode>>>,
    /// The key comparison function.
    pub cmp_function: BOSTreeCmpFunction,
    /// The optional free function for node data.
    pub free_function: Option<BOSTreeFreeFunction>,
}

/// The node structure.
#[derive(Debug)]
pub struct BOSNode {
    /// Number of nodes in the left subtree.
    pub left_child_count: u32,
    /// Number of nodes in the right subtree.
    pub right_child_count: u32,
    /// Cached depth of the node.
    pub depth: u32,
    /// Left child node.
    pub left_child_node: Option<Rc<RefCell<BOSNode>>>,
    /// Right child node.
    pub right_child_node: Option<Rc<RefCell<BOSNode>>>,
    /// Parent node (using a weak reference to avoid cycles).
    pub parent_node: Option<Weak<RefCell<BOSNode>>>,
    /// The key for this node.
    pub key: String,
    /// The associated data.
    pub data: Option<String>,
    /// Internal weak reference counter.
    pub weak_ref_count: u8,
    /// Validity flag for the weak reference.
    pub weak_ref_node_valid: u8,
}

/// Type alias for a key comparison function.
pub type BOSTreeCmpFunction = fn(&str, &str) -> i32;

/// Type alias for a free function which will be called on nodes
/// that are removed.
pub type BOSTreeFreeFunction = fn(&Rc<RefCell<BOSNode>>);

fn compute_depth(node: &Rc<RefCell<BOSNode>>) -> u32 {
    let n = node.borrow();
    let left = n.left_child_node.as_ref().map_or(0u32, |c| c.borrow().depth + 1);
    let right = n.right_child_node.as_ref().map_or(0u32, |c| c.borrow().depth + 1);
    left.max(right)
}

fn balance(node: &Rc<RefCell<BOSNode>>) -> i32 {
    let n = node.borrow();
    let left_depth = n
        .left_child_node
        .as_ref()
        .map_or(0i32, |c| c.borrow().depth as i32 + 1);
    let right_depth = n
        .right_child_node
        .as_ref()
        .map_or(0i32, |c| c.borrow().depth as i32 + 1);
    right_depth - left_depth
}

fn is_left_child_of(
    child: &Rc<RefCell<BOSNode>>,
    parent: &Rc<RefCell<BOSNode>>,
) -> bool {
    parent
        .borrow()
        .left_child_node
        .as_ref()
        .map_or(false, |c| Rc::ptr_eq(c, child))
}

fn rotate_right(
    tree: &mut BOSTree,
    p: &Rc<RefCell<BOSNode>>,
) -> Rc<RefCell<BOSNode>> {
    let l = p.borrow().left_child_node.as_ref().unwrap().clone();

    let p_parent_weak = p.borrow().parent_node.clone();
    let p_parent = p_parent_weak.as_ref().and_then(|w| w.upgrade());

    match &p_parent {
        Some(parent) => {
            if is_left_child_of(p, parent) {
                parent.borrow_mut().left_child_node = Some(l.clone());
            } else {
                parent.borrow_mut().right_child_node = Some(l.clone());
            }
        }
        None => {
            tree.root_node = Some(l.clone());
        }
    }

    l.borrow_mut().parent_node = p_parent_weak;

    let l_right = l.borrow().right_child_node.clone();
    let l_right_count = l.borrow().right_child_count;
    {
        let mut pm = p.borrow_mut();
        pm.left_child_node = l_right.clone();
        pm.left_child_count = l_right_count;
    }

    if let Some(child) = &l_right {
        child.borrow_mut().parent_node = Some(Rc::downgrade(p));
    }

    let p_depth = compute_depth(p);
    p.borrow_mut().depth = p_depth;

    l.borrow_mut().right_child_node = Some(p.clone());
    p.borrow_mut().parent_node = Some(Rc::downgrade(&l));

    let (p_left_count, p_right_count) = {
        let pb = p.borrow();
        (pb.left_child_count, pb.right_child_count)
    };
    l.borrow_mut().right_child_count = p_left_count + p_right_count + 1;

    let l_depth = compute_depth(&l);
    l.borrow_mut().depth = l_depth;

    l
}

fn rotate_left(
    tree: &mut BOSTree,
    p: &Rc<RefCell<BOSNode>>,
) -> Rc<RefCell<BOSNode>> {
    let r = p.borrow().right_child_node.as_ref().unwrap().clone();

    let p_parent_weak = p.borrow().parent_node.clone();
    let p_parent = p_parent_weak.as_ref().and_then(|w| w.upgrade());

    match &p_parent {
        Some(parent) => {
            if is_left_child_of(p, parent) {
                parent.borrow_mut().left_child_node = Some(r.clone());
            } else {
                parent.borrow_mut().right_child_node = Some(r.clone());
            }
        }
        None => {
            tree.root_node = Some(r.clone());
        }
    }

    r.borrow_mut().parent_node = p_parent_weak;

    let r_left = r.borrow().left_child_node.clone();
    let r_left_count = r.borrow().left_child_count;
    {
        let mut pm = p.borrow_mut();
        pm.right_child_node = r_left.clone();
        pm.right_child_count = r_left_count;
    }

    if let Some(child) = &r_left {
        child.borrow_mut().parent_node = Some(Rc::downgrade(p));
    }

    let p_depth = compute_depth(p);
    p.borrow_mut().depth = p_depth;

    r.borrow_mut().left_child_node = Some(p.clone());
    p.borrow_mut().parent_node = Some(Rc::downgrade(&r));

    let (p_left_count, p_right_count) = {
        let pb = p.borrow();
        (pb.left_child_count, pb.right_child_count)
    };
    r.borrow_mut().left_child_count = p_left_count + p_right_count + 1;

    let r_depth = compute_depth(&r);
    r.borrow_mut().depth = r_depth;

    r
}

impl BOSTree {
    /// Create a new tree with a mandatory comparison function and an optional free function.
    pub fn bostree_new(
        cmp_function: BOSTreeCmpFunction,
        free_function: Option<BOSTreeFreeFunction>,
    ) -> Self {
        BOSTree {
            root_node: None,
            cmp_function,
            free_function,
        }
    }

    /// Return the number of nodes in the tree.
    pub fn bostree_node_count(&self) -> u32 {
        match &self.root_node {
            Some(n) => {
                let nb = n.borrow();
                nb.left_child_count + nb.right_child_count + 1
            }
            None => 0,
        }
    }

    /// Insert a new member into the tree and return the associated node.
    pub fn bostree_insert(
        &mut self,
        key: String,
        data: Option<String>,
    ) -> Rc<RefCell<BOSNode>> {
        let mut current = self.root_node.clone();
        let mut parent: Option<Rc<RefCell<BOSNode>>> = None;
        let mut went_left = false;

        while let Some(node) = current {
            parent = Some(node.clone());
            let cmp = (self.cmp_function)(&key, &node.borrow().key);
            if cmp < 0 {
                node.borrow_mut().left_child_count += 1;
                let next = node.borrow().left_child_node.clone();
                current = next;
                went_left = true;
            } else {
                node.borrow_mut().right_child_count += 1;
                let next = node.borrow().right_child_node.clone();
                current = next;
                went_left = false;
            }
        }

        let new_node = Rc::new(RefCell::new(BOSNode {
            left_child_count: 0,
            right_child_count: 0,
            depth: 0,
            left_child_node: None,
            right_child_node: None,
            parent_node: parent.as_ref().map(|p| Rc::downgrade(p)),
            key,
            data,
            weak_ref_count: 1,
            weak_ref_node_valid: 1,
        }));

        let parent_node = match parent {
            None => {
                self.root_node = Some(new_node.clone());
                return new_node;
            }
            Some(p) => p,
        };

        if went_left {
            parent_node.borrow_mut().left_child_node = Some(new_node.clone());
        } else {
            parent_node.borrow_mut().right_child_node = Some(new_node.clone());
        }

        // Check if the depth changed (only when parent had exactly 0 children before).
        let xor_check = {
            let p = parent_node.borrow();
            p.left_child_node.is_some() ^ p.right_child_node.is_some()
        };

        if xor_check {
            parent_node.borrow_mut().depth += 1;

            let mut current_parent = parent_node;
            loop {
                let next_parent = current_parent
                    .borrow()
                    .parent_node
                    .as_ref()
                    .and_then(|w| w.upgrade());
                match next_parent {
                    None => break,
                    Some(np) => current_parent = np,
                }

                let (new_left_depth, new_right_depth) = {
                    let n = current_parent.borrow();
                    let l = n
                        .left_child_node
                        .as_ref()
                        .map_or(0u32, |c| c.borrow().depth + 1);
                    let r = n
                        .right_child_node
                        .as_ref()
                        .map_or(0u32, |c| c.borrow().depth + 1);
                    (l, r)
                };
                let max_depth = new_left_depth.max(new_right_depth);

                let old_depth = current_parent.borrow().depth;
                if old_depth != max_depth {
                    current_parent.borrow_mut().depth = max_depth;
                } else {
                    break;
                }

                if new_left_depth >= 2 && new_left_depth - 2 == new_right_depth {
                    let lcn = current_parent.borrow().left_child_node.clone();
                    if let Some(left_child) = &lcn {
                        if balance(left_child) > 0 {
                            rotate_left(self, left_child);
                        }
                    }
                    let cp = current_parent.clone();
                    current_parent = rotate_right(self, &cp);
                } else if new_right_depth >= 2 && new_left_depth + 2 == new_right_depth {
                    let rcn = current_parent.borrow().right_child_node.clone();
                    if let Some(right_child) = &rcn {
                        if balance(right_child) < 0 {
                            rotate_right(self, right_child);
                        }
                    }
                    let cp = current_parent.clone();
                    current_parent = rotate_left(self, &cp);
                }
            }
        }

        new_node
    }

    /// Remove a given node from the tree.
