                .and_then(|w| w.upgrade())
                .unwrap();

            if is_left_child_of(&candidate, &bubble_start) {
                bubble_start.borrow_mut().left_child_node = lost_child.clone();
            } else {
                bubble_start.borrow_mut().right_child_node = lost_child.clone();
            }

            if let Some(lc) = &lost_child {
                lc.borrow_mut().parent_node = Some(Rc::downgrade(&bubble_start));
            }

            // Anchor candidate where node was.
            let node_parent_weak = node.borrow().parent_node.clone();
            let node_parent = node_parent_weak.as_ref().and_then(|w| w.upgrade());
            match &node_parent {
                Some(np) => {
                    if is_left_child_of(&node, np) {
                        np.borrow_mut().left_child_node = Some(candidate.clone());
                    } else {
                        np.borrow_mut().right_child_node = Some(candidate.clone());
                    }
                }
                None => {
                    self.root_node = Some(candidate.clone());
                }
            }
            candidate.borrow_mut().parent_node = node_parent_weak;

            // Copy node's (possibly modified) children to candidate.
            let (node_left, node_left_count, node_right, node_right_count) = {
                let n = node.borrow();
                (
                    n.left_child_node.clone(),
                    n.left_child_count,
                    n.right_child_node.clone(),
                    n.right_child_count,
                )
            };
            {
                let mut cb = candidate.borrow_mut();
                cb.left_child_node = node_left.clone();
                cb.left_child_count = node_left_count;
                cb.right_child_node = node_right.clone();
                cb.right_child_count = node_right_count;
            }
            if let Some(lc) = &node_left {
                lc.borrow_mut().parent_node = Some(Rc::downgrade(&candidate));
            }
            if let Some(rc) = &node_right {
                rc.borrow_mut().parent_node = Some(Rc::downgrade(&candidate));
            }

            // Rebalance from bubble_start up to candidate.
            if !Rc::ptr_eq(&bubble_start, &node) {
                let mut current = bubble_start.clone();
                while !Rc::ptr_eq(&current, &candidate) {
                    let d = compute_depth(&current);
                    current.borrow_mut().depth = d;

                    let bal = balance(&current);
                    if bal > 1 {
                        let rcn = current.borrow().right_child_node.clone();
                        if let Some(rc) = &rcn {
                            if balance(rc) < 0 {
                                rotate_right(self, rc);
                            }
                        }
                        let c = current.clone();
                        current = rotate_left(self, &c);
                    } else if bal < -1 {
                        let lcn = current.borrow().left_child_node.clone();
                        if let Some(lc) = &lcn {
                            if balance(lc) > 0 {
                                rotate_left(self, lc);
                            }
                        }
                        let c = current.clone();
                        current = rotate_right(self, &c);
                    }

                    let parent = current
                        .borrow()
                        .parent_node
                        .as_ref()
                        .and_then(|w| w.upgrade());
                    match parent {
                        Some(p) => current = p,
                        None => break,
                    }
                }
            }

            // Fixup candidate's depth.
            let cd = compute_depth(&candidate);
            candidate.borrow_mut().depth = cd;

            bubble_up = candidate
                .borrow()
                .parent_node
                .as_ref()
                .and_then(|w| w.upgrade());

            // Decrement candidate's parent's child count.
            if let Some(bu) = &bubble_up {
                if is_left_child_of(&candidate, bu) {
                    bu.borrow_mut().left_child_count -= 1;
                } else {
                    bu.borrow_mut().right_child_count -= 1;
                }
            }
        } else {
            // node has at most one child.
            let node_parent_weak = node.borrow().parent_node.clone();
            let node_parent = node_parent_weak.as_ref().and_then(|w| w.upgrade());

            if node_parent.is_none() {
                let (left, right) = {
                    let n = node.borrow();
                    (n.left_child_node.clone(), n.right_child_node.clone())
                };
                if let Some(l) = &left {
                    self.root_node = Some(l.clone());
                    l.borrow_mut().parent_node = None;
                } else {
                    self.root_node = right.clone();
                    if let Some(r) = &right {
                        r.borrow_mut().parent_node = None;
                    }
                }
                bubble_up = None;
            } else {
                let (left, left_count, right, right_count) = {
                    let n = node.borrow();
                    (
                        n.left_child_node.clone(),
                        n.left_child_count,
                        n.right_child_node.clone(),
                        n.right_child_count,
                    )
                };
                let (candidate, candidate_count) = if right.is_some() {
                    (right.clone(), right_count)
                } else {
                    (left.clone(), left_count)
                };

                let np = node_parent.unwrap();
                if is_left_child_of(&node, &np) {
                    let mut npm = np.borrow_mut();
                    npm.left_child_node = candidate.clone();
                    npm.left_child_count = candidate_count;
                } else {
                    let mut npm = np.borrow_mut();
                    npm.right_child_node = candidate.clone();
                    npm.right_child_count = candidate_count;
                }

                if let Some(c) = &candidate {
                    c.borrow_mut().parent_node = Some(Rc::downgrade(&np));
                }

                bubble_up = Some(np);
            }
        }

        // Bubble up the tree: rebalance as needed and update child counts.
        let mut bubbling_finished = false;
        let mut current_bubble = bubble_up;
        while let Some(bu) = current_bubble.clone() {
            if !bubbling_finished {
                let (left_depth, right_depth) = {
                    let n = bu.borrow();
                    let l = n
                        .left_child_node
                        .as_ref()
                        .map_or(0u32, |c| c.borrow().depth + 1);
                    let r = n
                        .right_child_node
                        .as_ref()
                        .map_or(0u32, |c| c.borrow().depth + 1);
                    (l, r)
                };
                let new_depth = left_depth.max(right_depth);
                let depth_changed = new_depth != bu.borrow().depth;
                bu.borrow_mut().depth = new_depth;

                let bal = balance(&bu);
                let mut new_bu = bu.clone();
                if bal < -1 {
                    let lcn = bu.borrow().left_child_node.clone();
                    if let Some(lc) = &lcn {
                        if balance(lc) > 0 {
                            rotate_left(self, lc);
                        }
                    }
                    new_bu = rotate_right(self, &bu);
                } else if bal > 1 {
                    let rcn = bu.borrow().right_child_node.clone();
                    if let Some(rc) = &rcn {
                        if balance(rc) < 0 {
                            rotate_right(self, rc);
                        }
                    }
                    new_bu = rotate_left(self, &bu);
                } else if !depth_changed {
                    bubbling_finished = true;
                }
                current_bubble = Some(new_bu);
            }

            let bu_now = current_bubble.as_ref().unwrap().clone();
            let bu_parent = bu_now
                .borrow()
                .parent_node
                .as_ref()
                .and_then(|w| w.upgrade());
            if let Some(parent) = &bu_parent {
                if is_left_child_of(&bu_now, parent) {
                    parent.borrow_mut().left_child_count -= 1;
                } else {
                    parent.borrow_mut().right_child_count -= 1;
                }
            }
            current_bubble = bu_parent;
        }

        node.borrow_mut().weak_ref_node_valid = 0;
        // Detach node from the tree.
        {
            let mut nm = node.borrow_mut();
            nm.left_child_node = None;
            nm.right_child_node = None;
            nm.parent_node = None;
        }
        self.bostree_node_weak_unref(&node);
    }

    /// Decrease the weak reference count for a node.
    pub fn bostree_node_weak_unref(
        &mut self,
        node: &Rc<RefCell<BOSNode>>,
    ) -> Option<Rc<RefCell<BOSNode>>> {
        node.borrow_mut().weak_ref_count -= 1;
        let count = node.borrow().weak_ref_count;
        if count == 0 {
            if let Some(free_fn) = self.free_function {
                free_fn(node);
            }
            None
        } else if node.borrow().weak_ref_node_valid != 0 {
            Some(node.clone())
        } else {
            None
        }
    }

    /// Lookup a node in the tree by its key.
    pub fn bostree_lookup(&self, key: &str) -> Option<Rc<RefCell<BOSNode>>> {
        let mut current = self.root_node.clone();
        while let Some(node) = current {
            let cmp = (self.cmp_function)(key, &node.borrow().key);
            if cmp == 0 {
                return Some(node);
            } else if cmp < 0 {
                let next = node.borrow().left_child_node.clone();
                current = next;
            } else {
                let next = node.borrow().right_child_node.clone();
                current = next;
            }
        }
        None
    }

    /// Return the node at the given in-order index (starting at 0).
    pub fn bostree_select(&self, mut index: u32) -> Option<Rc<RefCell<BOSNode>>> {
        let mut current = self.root_node.clone();
        while let Some(node) = current {
            let left_count = node.borrow().left_child_count;
            if left_count <= index {
                index -= left_count;
                if index == 0 {
                    return Some(node);
                }
                index -= 1;
                let next = node.borrow().right_child_node.clone();
                current = next;
            } else {
                let next = node.borrow().left_child_node.clone();
                current = next;
            }
        }
        None
    }

    /// Print the tree in dot format (only available in debug builds).
    #[cfg(debug_assertions)]
    pub fn bostree_print(&self) {
        fn helper(node: &Rc<RefCell<BOSNode>>) {
            let n = node.borrow();
            println!(
                "  {} [label=\"\\N ({},{},{})\"];",
                n.key, n.left_child_count, n.right_child_count, n.depth
            );
            if let Some(p) = n.parent_node.as_ref().and_then(|w| w.upgrade()) {
                println!("  {} -> {} [color=green];", n.key, p.borrow().key);
            }
            if let Some(l) = &n.left_child_node {
                println!("  {} -> {}", n.key, l.borrow().key);
                helper(l);
            }
            if let Some(r) = &n.right_child_node {
                println!("  {} -> {}", n.key, r.borrow().key);
                helper(r);
            }
        }
        if let Some(root) = &self.root_node {
            println!("digraph {{");
            println!("  ordering = out;");
            helper(root);
            println!("}}");
        }
    }
}

impl Drop for BOSTree {
    fn drop(&mut self) {
        // Walk the tree iteratively to avoid recursive Drop of Rc which may
        // overflow the stack for large trees.
        let mut current = self.root_node.take();
        while let Some(node) = current {
            // Descend into the left-most leaf
            let mut leaf = node;
            loop {
                let next = leaf.borrow_mut().left_child_node.take();
                match next {
                    Some(n) => leaf = n,
                    None => break,
                }
            }
            // Detach right child (if any) and walk to it
            let right = leaf.borrow_mut().right_child_node.take();
            if right.is_some() {
                // Place right as next iteration root; but need to handle parent
                let parent = leaf
                    .borrow()
                    .parent_node
                    .as_ref()
                    .and_then(|w| w.upgrade());
                if let Some(p) = parent {
                    // Replace leaf in parent with right
                    let mut pm = p.borrow_mut();
                    if pm
                        .left_child_node
                        .as_ref()
                        .map_or(false, |c| Rc::ptr_eq(c, &leaf))
                    {
                        pm.left_child_node = right.clone();
                    } else if pm
                        .right_child_node
                        .as_ref()
                        .map_or(false, |c| Rc::ptr_eq(c, &leaf))
                    {
                        pm.right_child_node = right.clone();
                    }
                    if let Some(r) = &right {
                        r.borrow_mut().parent_node = Some(Rc::downgrade(&p));
                    }
                    current = self.root_node.take();
                    if current.is_none() {
                        current = right;
                    }
                } else {
                    current = right;
                }
                continue;
            }
            // leaf has no children — detach from parent
            let parent = leaf
                .borrow()
                .parent_node
                .as_ref()
                .and_then(|w| w.upgrade());
            if let Some(p) = parent {
                let mut pm = p.borrow_mut();
                if pm
                    .left_child_node
                    .as_ref()
                    .map_or(false, |c| Rc::ptr_eq(c, &leaf))
                {
                    pm.left_child_node = None;
                } else if pm
                    .right_child_node
                    .as_ref()
                    .map_or(false, |c| Rc::ptr_eq(c, &leaf))
                {
                    pm.right_child_node = None;
                }
                drop(pm);
                leaf.borrow_mut().parent_node = None;
                current = Some(p);
            } else {
                current = None;
            }
        }
    }
}

/// Increase the weak reference count for a node and return the node.
pub fn bostree_node_weak_ref(node: &Rc<RefCell<BOSNode>>) -> Rc<RefCell<BOSNode>> {
    {
        let mut n = node.borrow_mut();
        assert!(n.weak_ref_count < 127);
        assert!(n.weak_ref_count > 0);
        n.weak_ref_count += 1;
    }
    node.clone()
}

/// Return the next node in an in-order traversal.
pub fn bostree_next_node(node: &Rc<RefCell<BOSNode>>) -> Option<Rc<RefCell<BOSNode>>> {
    let right = node.borrow().right_child_node.clone();
    if let Some(mut current) = right {
        loop {
            let left = current.borrow().left_child_node.clone();
            match left {
                Some(n) => current = n,
                None => return Some(current),
            }
        }
    } else {
        let mut current = node.clone();
        loop {
            let parent = current
                .borrow()
                .parent_node
                .as_ref()
                .and_then(|w| w.upgrade());
            match parent {
                None => return None,
                Some(p) => {
                    let is_right = p
                        .borrow()
                        .right_child_node
                        .as_ref()
                        .map_or(false, |c| Rc::ptr_eq(c, &current));
                    if is_right {
                        current = p;
                    } else {
                        return Some(p);
                    }
                }
            }
        }
    }
}

/// Return the previous node in an in-order traversal.
pub fn bostree_previous_node(node: &Rc<RefCell<BOSNode>>) -> Option<Rc<RefCell<BOSNode>>> {
    let left = node.borrow().left_child_node.clone();
    if let Some(mut current) = left {
        loop {
            let right = current.borrow().right_child_node.clone();
            match right {
                Some(n) => current = n,
                None => return Some(current),
            }
        }
    } else {
        let mut current = node.clone();
        loop {
            let parent = current
                .borrow()
                .parent_node
                .as_ref()
                .and_then(|w| w.upgrade());
            match parent {
                None => return None,
                Some(p) => {
                    let is_left = p
                        .borrow()
                        .left_child_node
                        .as_ref()
                        .map_or(false, |c| Rc::ptr_eq(c, &current));
                    if is_left {
                        current = p;
                    } else {
                        return Some(p);
                    }
                }
            }
        }
    }
}

/// Return the rank (in-order index) of the given node.
pub fn bostree_rank(node: &Rc<RefCell<BOSNode>>) -> u32 {
    let mut counter = node.borrow().left_child_count;
    let mut current = node.clone();
    loop {
        let parent = current
            .borrow()
            .parent_node
            .as_ref()
            .and_then(|w| w.upgrade());
        match parent {
            None => return counter,
            Some(p) => {
                let is_right = p
                    .borrow()
                    .right_child_node
                    .as_ref()
                    .map_or(false, |c| Rc::ptr_eq(c, &current));
                if is_right {
                    counter += 1 + p.borrow().left_child_count;
                }
                current = p;
            }
        }
    }
}
