pub type BOSTreeFreeFunction = fn(&Rc<RefCell<BOSNode>>);

fn compute_depth(node: &Rc<RefCell<BOSNode>>) -> u32 {
    let n = node.borrow();
    let left = n.left_child_node.as_ref().map_or(0u32, |c| c.borrow().depth + 1);
    let right = n.right_child_node.as_ref().map_or(0u32, |c| c.borrow().depth + 1);
