633	    /// Lookup a node in the tree by its key.
634	    pub fn bostree_lookup(&self, key: &str) -> Option<Rc<RefCell<BOSNode>>> {
635	        let mut current = self.root_node.clone();
636	        while let Some(node) = current {
637	            let cmp = (self.cmp_function)(key, &node.borrow().key);
638	            if cmp == 0 {
639	                return Some(node);
640	            } else if cmp < 0 {
641	                let next = node.borrow().left_child_node.clone();
642	                current = next;
643	            } else {
644	                let next = node.borrow().right_child_node.clone();
645	                current = next;
646	            }
647	        }
648	        None
649	    }
