652	    pub fn bostree_select(&self, mut index: u32) -> Option<Rc<RefCell<BOSNode>>> {
653	        let mut current = self.root_node.clone();
654	        while let Some(node) = current {
655	            let left_count = node.borrow().left_child_count;
656	            if left_count <= index {
657	                index -= left_count;
658	                if index == 0 {
