703	    fn drop(&mut self) {
704	        // Walk the tree iteratively to avoid recursive Drop of Rc which may
705	        // overflow the stack for large trees.
706	        let mut current = self.root_node.take();
707	        while let Some(node) = current {
708	            // Descend into the left-most leaf
709	            let mut leaf = node;
710	            loop {
711	                let next = leaf.borrow_mut().left_child_node.take();
712	                match next {
713	                    Some(n) => leaf = n,
714	                    None => break,
715	                }
716	            }
717	            // Detach right child (if any) and walk to it
718	            let right = leaf.borrow_mut().right_child_node.take();
719	            if right.is_some() {
720	                // Place right as next iteration root; but need to handle parent
721	                let parent = leaf
722	                    .borrow()
723	                    .parent_node
724	                    .as_ref()
725	                    .and_then(|w| w.upgrade());
726	                if let Some(p) = parent {
727	                    // Replace leaf in parent with right
728	                    let mut pm = p.borrow_mut();
729	                    if pm
730	                        .left_child_node
731	                        .as_ref()
732	                        .map_or(false, |c| Rc::ptr_eq(c, &leaf))
733	                    {
734	                        pm.left_child_node = right.clone();
735	                    } else if pm
736	                        .right_child_node
737	                        .as_ref()
738	                        .map_or(false, |c| Rc::ptr_eq(c, &leaf))
739	                    {
740	                        pm.right_child_node = right.clone();
741	                    }
742	                    if let Some(r) = &right {
743	                        r.borrow_mut().parent_node = Some(Rc::downgrade(&p));
744	                    }
745	                    current = self.root_node.take();
746	                    if current.is_none() {
