impl Drop for BOSTree {
    fn drop(&mut self) {
        // Iteratively dismantle the tree to avoid deep recursive Drop on large trees.
        let mut stack: Vec<Rc<RefCell<BOSNode>>> = Vec::new();
        if let Some(root) = self.root_node.take() {
            stack.push(root);
        }
        while let Some(node) = stack.pop() {
            let (left, right) = {
                let mut n = node.borrow_mut();
                (n.left_child_node.take(), n.right_child_node.take())
            };
            if let Some(l) = left {
                stack.push(l);
            }
            if let Some(r) = right {
                stack.push(r);
            }
        }
    }
}

